#include "buffer.h"
#include <string.h>

/* Copy `raw_len` bytes of `raw` into the packet's data field. */
void parse_packet(packet_t *p, const char *raw, size_t raw_len) {
    memcpy(p->data, raw, raw_len);
    p->len = raw_len;
}
